const { MongoClient } = require('mongodb');
const crypto = require('crypto');

class CouponRedemptionSystem {
  constructor(connectionString, databaseName) {
    this.client = new MongoClient(connectionString);
    this.db = null;
    this.couponsCollection = null;
    this.redemptionsCollection = null;
  }

  async initialize() {
    await this.client.connect();
    this.db = this.client.db(this.databaseName);
    this.couponsCollection = this.db.collection('coupons');
    this.redemptionsCollection = this.db.collection('redemptions');
    
    await this.couponsCollection.createIndex({ "code": 1 }, { unique: true });
    await this.couponsCollection.createIndex({ "expiresAt": 1 }, { expireAfterSeconds: 0 });
    await this.redemptionsCollection.createIndex({ "userId": 1, "couponCode": 1 }, { unique: true });
  }

  async redeemCoupon(userId, couponCode, purchaseAmount) {
    const session = this.client.startSession();
    
    try {
      await session.startTransaction();
      
      const coupon = await this.couponsCollection.findOne(
        { 
          code: couponCode,
          isActive: true,
          expiresAt: { $gt: new Date() }
        },
        { session }
      );
      
      if (!coupon) {
        throw new Error('Invalid or expired coupon');
      }
      
      const existingRedemption = await this.redemptionsCollection.findOne(
        { userId, couponCode },
        { session }
      );
      
      if (existingRedemption) {
        throw new Error('Coupon already redeemed by this user');
      }
      
      const updateResult = await this.couponsCollection.updateOne(
        { 
          code: couponCode,
          isActive: true,
          expiresAt: { $gt: new Date() },
          usedCount: { $lt: coupon.maxUses }
        },
        { 
          $inc: { usedCount: 1 },
          $push: { redeemedBy: userId }
        },
        { session }
      );
      
      if (updateResult.matchedCount === 0) {
        throw new Error('Coupon is no longer available');
      }
      
      const discountAmount = this.calculateDiscount(coupon, purchaseAmount);
      
      await this.redemptionsCollection.insertOne({
        userId,
        couponCode,
        discountAmount,
        originalAmount: purchaseAmount,
        timestamp: new Date(),
        transactionId: crypto.randomBytes(16).toString('hex')
      }, { session });
      
      await session.commitTransaction();
      
      return {
        success: true,
        discountAmount,
        finalAmount: purchaseAmount - discountAmount,
        couponCode
      };
      
    } catch (error) {
      await session.abortTransaction();
      throw error;
    } finally {
      await session.endSession();
    }
  }

  calculateDiscount(coupon, amount) {
    if (coupon.type === 'percentage') {
      return amount * (coupon.value / 100);
    } else if (coupon.type === 'fixed') {
      return Math.min(coupon.value, amount);
    }
    return 0;
  }

  async validateCoupon(couponCode) {
    const coupon = await this.couponsCollection.findOne({
      code: couponCode,
      isActive: true,
      expiresAt: { $gt: new Date() }
    });
    
    return !!coupon;
  }

  async getRedemptionHistory(userId, limit = 10) {
    return await this.redemptionsCollection.find({ userId })
      .sort({ timestamp: -1 })
      .limit(limit)
      .toArray();
  }

  async cleanupExpiredCoupons() {
    const session = this.client.startSession();
    
    try {
      await session.startTransaction();
      
      const expiredCoupons = await this.couponsCollection.find({
        expiresAt: { $lt: new Date() },
        isActive: true
      }).toArray();
      
      for (const coupon of expiredCoupons) {
        await this.couponsCollection.updateOne(
          { code: coupon.code },
          { $set: { isActive: false } },
          { session }
        );
      }
      
      await session.commitTransaction();
    } catch (error) {
      await session.abortTransaction();
      throw error;
    } finally {
      await session.endSession();
    }
  }
}

module.exports = CouponRedemptionSystem;